document.addEventListener("DOMContentLoaded",()=>{const grid=document.querySelector(".main-videos__grid");if(!grid)return;let cards=Array.from(grid.querySelectorAll(".card"));function render(cardsArray){grid.innerHTML="",cardsArray.forEach((card,index)=>{card.classList.remove("card--xl"),card.classList.add("card--s"),0===index&&(card.classList.remove("card--s"),card.classList.add("card--xl")),grid.appendChild(card)})}cards.sort(()=>Math.random()-.5),render(cards),grid.addEventListener("click",e=>{const playButton=e.target.closest(".card__play");if(!playButton)return;const clickedCard=playButton.closest(".card");if(!clickedCard)return;const currentCards=Array.from(grid.querySelectorAll(".card")),clickedIndex=currentCards.indexOf(clickedCard);if(-1===clickedIndex)return;render([...currentCards.slice(clickedIndex),...currentCards.slice(0,clickedIndex)])})});